const input = $input.first().json || {};
const candidates = [input, input.params || {}, input.input || {}, input.data || {}];
let userText = '';
let chatId = '';
let source = 'comment';

for (const obj of candidates) {
  if (!obj || typeof obj !== 'object') continue;
  userText = userText
    || obj.user_message
    || obj.text
    || obj.message
    || obj.query
    || obj.content
    || obj.input
    || '';
  chatId = chatId || obj.chat_id || obj.chatId || '';
  source = obj.source || source;
}

if (!userText && typeof input === 'string') userText = input;

const text = String(userText || '').trim();

// Stopwords để tránh match nhầm variation (vd "không", "có", "giá", "shop", "ơi"...)
const STOPWORDS = new Set(['không','khong','có','co','giá','gia','sao','thế','the','nào','nao','ạ','a','đi','di','shop','ad','ơi','oi','mua','order','chốt','chot','đặt','dat','nhé','nhe','nha','với','voi','cho','xin','gửi','gui','ảnh','anh','mẫu','mau','váy','vay','áo','ao','quần','quan','thế','the']);

// Parse SKU (VD01, vd28, vd 5, VD-12) — giữ raw match để detect separator giữa SKU và variation
const rawMatch = text.match(/\b(vd[-\s_]?\d{1,3})\b/i);
let sku = '';
let variation = '';
let queryTerm = '';

if (rawMatch) {
  const raw = rawMatch[1];
  sku = raw.toUpperCase().replace(/[-\s_]/g, '');

  // Tìm variation ngay sau raw SKU: 1+ separator (space/dash/underscore) + word 2-15 ký tự (cho phép VN có dấu)
  const escaped = raw.replace(/[-\/\\^$*+?.()|[\]{}]/g, '\\$&');
  const varRegex = new RegExp(escaped + '[\\s\\-_]+([a-zA-ZÀ-ỹ]{2,15})', 'i');
  const varMatch = text.match(varRegex);
  if (varMatch && varMatch[1]) {
    const candidate = varMatch[1].toLowerCase();
    if (!STOPWORDS.has(candidate)) variation = candidate;
  }

  queryTerm = variation ? `${sku}-${variation}` : sku;
}

return [{
  json: {
    user_text: text,
    chat_id: String(chatId || ''),
    source: source,
    sku,
    variation,
    query_term: queryTerm,
    has_sku: !!sku,
  }
}];

const items = $input.all();
const input = $node["Extract SKU & Variation"].json;

// Defensive: if upstream errored, return empty
const allFiles = [];
for (const item of items) {
  const files = item.json && item.json.files;
  if (Array.isArray(files)) allFiles.push(...files);
}

const imageUrls = allFiles.slice(0, 3).map(f => ({
  id: f.id,
  name: f.name,
  url: `https://drive.google.com/uc?id=${f.id}&export=download`,
  thumb: f.thumbnailLink || `https://drive.google.com/thumbnail?id=${f.id}&sz=w800`,
  webView: f.webContentLink || `https://drive.google.com/file/d/${f.id}/view`,
}));

return [{
  json: {
    sku: input.sku,
    variation: input.variation,
    query_term: input.query_term,
    user_text: input.user_text,
    chat_id: input.chat_id,
    source: input.source,
    found: imageUrls.length > 0,
    count: imageUrls.length,
    image_urls: imageUrls,
    primary_url: imageUrls[0] ? imageUrls[0].url : null,
  }
}];

const input = $node["Extract SKU & Variation"].json;
return [{
  json: {
    sku: input.sku,
    variation: input.variation,
    query_term: input.query_term,
    user_text: input.user_text,
    chat_id: input.chat_id,
    source: input.source,
    found: false,
    count: 0,
    image_urls: [],
    primary_url: null,
    reason: 'NO_SKU_DETECTED',
  }
}];
